import java.io.*;  // Import of InputStreamReader for reading a file as text streams; FileInputStream to read an actual input stream from another medium (file); BufferedReader/FileWriter etc., necessary when dealing with characters & bytes, not primitives or objects in Java like int and long are the ones that go into files.
import java.util.*;  // For using List for our Scanner; we'll need to use Iterator later on down below...
                     /*Scanner (and InputStreamReader), ArrayList etc., which come bundled with core classes, so no external libraries here needed*/   
class java_51157_FileScanner_A03 {  
 public static void main(String[] args) throws Exception{  // We will pass a string argument to the program that specifies where on your computer this file should be run from. This is often useful for testing of scripts in different directories or environments (e.g., running JUnit tests inside an IDE, working with remote files/services etc.)
    File dir = new File(".");  // Get current directory object...  
        printFilesIn(dir);         /* ... and pass it to the method that we'll call later */    
 }      
 private static void printFilesIn(File f) throws Exception {      /* This is a recursive function. It calls itself, until there are no files left in this directory or subdirectories*/    // Create an object of FileScanner – it’s like Scanner for file   ...    
        if (f == null || !f.exists()) return;       // If nothing to scan… exit the method early with a successful result...      /* The argument is assumed here that you want files and directories in your current directory, not subdirectories within them */  File[] list = f.listFiles();    
        if (list == null || list.length == 0) return;         // If nothing to scan… exit the method early with a successful result...   /* The argument is assumed here that you want files and directories in your current directory, not subdirectories within them */  for(File ff : Objects.requireNonNull(list)) {   
            if (ff.isDirectory()) printFilesIn(ff);       // If the file name matches what we’re looking to find... call this method recursively ...   /* The argument is assumed here that you want files and directories in your current directory, not subdirectories within them */  else {       
                System.out.println("File: " + ff.getName()+": ");      // Print the file name then its content if it's a regular (not symlink or device) File...   /* The argument is assumed here that you want to print out all files in directories but not show their contents */  BufferedReader br = new BufferedReader(new InputStreamReader(new FileInputStream(ff)));       
                String line;         // Declare a variable for the lines read from our file...   /* The argument is assumed here that you want to print out all files in directories but not show their contents */  while ((line=br.readLine()) != null) {          System.out.println(line);      }       br.close();    
            }}    // Close the BufferedReader after reading...   /* The argument is assumed here that you want to print out all files in directories but not show their contents */ }}});        // End of main method, close your IDE and run this file for testing purposes!           }};// closing curly braces are important when declaring a class or methods.